static string fmt2D(const vector<vector<int>>& a) {
  if (a.empty()) return "[]";
  string out = "[";
  for (size_t i = 0; i < a.size(); i++) {
    if (i) out += " ";
    out += "[";
    for (size_t j = 0; j < a[i].size(); j++) {
      if (j) out += " ";
      out += to_string(a[i][j]);
    }
    out += "]";
  }
  out += "]";
  return out;
}
int main() {
  ios::sync_with_stdio(false);
  cin.tie(nullptr);
  string line;
  while (getline(cin, line)) {
    if (line.empty()) continue;
    vector<vector<int>> intervals;
    for (string part; ; ) {
      auto pos = line.find('|');
      part = (pos == string::npos) ? line : line.substr(0, pos);
      if (pos != string::npos) line = line.substr(pos + 1);
      part.erase(0, part.find_first_not_of(" 	
"));
      part.erase(part.find_last_not_of(" 	
") + 1);
      if (!part.empty()) {
        istringstream iss(part);
        int a, b;
        iss >> a >> b;
        intervals.push_back({a, b});
      }
      if (pos == string::npos) break;
    }
    auto res = merge(intervals);
    cout << fmt2D(res) << "\n";
  }
  return 0;
}

