func decodeString(s string) string {
	type frame struct{ str string; num int }
	stack := []frame{}
	current := ""
	num := 0
	for _, ch := range s {
		switch {
		case ch >= '0' && ch <= '9':
			num = num*10 + int(ch-'0')
		case ch == '[':
			stack = append(stack, frame{current, num})
			current, num = "", 0
