def search_range(nums: list[int], target: int) -> list[int]:
    def find_bound(is_left: bool) -> int:
        lo, hi, bound = 0, len(nums) - 1, -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if nums[mid] == target:
                bound = mid
                if is_left: hi = mid - 1
                else: lo = mid + 1
            elif nums[mid] < target:
                lo = mid + 1
            else:
                hi = mid - 1
        return bound
    return [find_bound(True), find_bound(False)]

