 */
function rotate(nums, k) {
    const n = nums.length;
    k %= n;
    function reverse(lo, hi) {
        while (lo < hi) { [nums[lo++], nums[hi--]] = [nums[hi], nums[lo-1]]; }
    }
    reverse(0, n-1); reverse(0, k-1); reverse(k, n-1);
}

