package main

import (
	"container/heap"
	"fmt"
)

type MaxHeap []int
func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i] > h[j] }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MaxHeap) Push(x any)        { *h = append(*h, x.(int)) }
func (h *MaxHeap) Pop() any          { old:=*h; x:=old[len(old)-1]; *h=old[:len(old)-1]; return x }

type MinHeap []int
func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x any)        { *h = append(*h, x.(int)) }
func (h *MinHeap) Pop() any          { old:=*h; x:=old[len(old)-1]; *h=old[:len(old)-1]; return x }

type MedianFinder struct{ small *MaxHeap; large *MinHeap }

func newMedianFinder() *MedianFinder { s:=&MaxHeap{}; l:=&MinHeap{}; heap.Init(s); heap.Init(l); return &MedianFinder{s,l} }

func (mf *MedianFinder) addNum(num int) {
	heap.Push(mf.small, num)
	if mf.small.Len()>0 && mf.large.Len()>0 && (*mf.small)[0] > (*mf.large)[0] {
		heap.Push(mf.large, heap.Pop(mf.small))
	}
	if mf.small.Len() > mf.large.Len()+1 { heap.Push(mf.large, heap.Pop(mf.small)) } else if mf.large.Len() > mf.small.Len() { heap.Push(mf.small, heap.Pop(mf.large)) }
}

func (mf *MedianFinder) findMedian() float64 {
	if mf.small.Len() > mf.large.Len() { return float64((*mf.small)[0]) }
	return float64((*mf.small)[0]+(*mf.large)[0]) / 2.0
}

func main() {
	mf := newMedianFinder(); mf.addNum(1); mf.addNum(2)
	fmt.Println(mf.findMedian())  // 1.5
	mf.addNum(3); fmt.Println(mf.findMedian())  // 2
}

