import "fmt"

func minCut(s string) int {
	n := len(s)
	isPalin := make([][]bool, n)
	for i := range isPalin { isPalin[i] = make([]bool, n) }
	for i := n-1; i >= 0; i-- { for j := i; j < n; j++ { isPalin[i][j] = s[i]==s[j] && (j-i<=2 || isPalin[i+1][j-1]) } }
	dp := make([]int, n)
	for i := range dp { dp[i] = i }
	for i := 1; i < n; i++ {
		if isPalin[0][i] { dp[i]=0; continue }
		for j := 1; j <= i; j++ { if isPalin[j][i] && dp[j-1]+1 < dp[i] { dp[i]=dp[j-1]+1 } }
	}
	return dp[n-1]
}

