function canReach(arr, start) {
    const n = arr.length;
    const visited = new Set();
    const queue = [start];
    while (queue.length) {
        const i = queue.shift();
        if (arr[i] === 0) return true;
        if (visited.has(i)) continue;
        visited.add(i);
        for (const ni of [i + arr[i], i - arr[i]])
            if (ni >= 0 && ni < n && !visited.has(ni)) queue.push(ni);
    }
    return false;
}

