package main

import "fmt"

func canReach(arr []int, start int) bool {
	n := len(arr)
	visited := map[int]bool{}
	queue := []int{start}
	for len(queue) > 0 {
		i := queue[0]; queue = queue[1:]
		if arr[i] == 0 { return true }
		if visited[i] { continue }
		visited[i] = true
		for _, ni := range []int{i+arr[i], i-arr[i]} {
			if ni >= 0 && ni < n && !visited[ni] { queue = append(queue, ni) }
		}
	}
	return false
}

func main() {
	fmt.Println(canReach([]int{4,2,3,0,3,1,2}, 5))  // true
	fmt.Println(canReach([]int{3,0,2,1,2}, 2))        // false
}

